  beforeEach(async () => {
    await TestBed.configureTestingModule({
      imports: [StaffListComponent]
    })
    .compileComponents();

    fixture = TestBed.createComponent(StaffListComponent);
    component = fixture.componentInstance;
    fixture.detectChanges();
  });

  it('should create', () => {
